import React, { useState, useCallback, useMemo, useRef } from 'react';
import {
  Button,
  Select,
  MoneyInput,
  dispatchAppToast,
  LinPageLayout,
  ErpListHeaderFilters,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { hasPermissionCode, useOpeningBalancePermissions } from '../../../hooks/useOpeningBalancePermissions';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { OpeningBalanceDto } from '../../../services/kt/models';
import { yearOptions } from '../../../constants/voucher';
import { openingBalancePageLabels } from '../../../constants/openingBalancePageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { formatVnd } from '../../../utils/formatters';
import { FormMode, isEditingMode, isViewMode } from '../../../components/form/FormMode';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-so-du-dau-ky';
const PAGE_ID = 'kt-so-du-dau-ky';
const labels = openingBalancePageLabels.soDuDauKy;

const cloneItems = (rows: OpeningBalanceDto[]): OpeningBalanceDto[] =>
  rows.map(row => ({ ...row }));

const SoDuDauKyPage: React.FC = () => {
  void hasPermissionCode;
  const { canWrite } = useOpeningBalancePermissions();
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningBalanceDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [formMode, setFormMode] = useState(FormMode.View);
  const snapshotRef = useRef<OpeningBalanceDto[]>([]);

  const isEditing = isEditingMode(formMode);
  const isView = isViewMode(formMode);
  const hasRows = items.length > 0;

  const load = useCallback(() => {
    setLoading(true);
    ktService.getOpeningBalances(Number(year))
      .then(data => {
        setItems(data);
        setFormMode(FormMode.View);
      })
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateItem = (idx: number, field: 'debitBalance' | 'creditBalance', val: number) => {
    setItems(prev => prev.map((it, i) => (i === idx ? { ...it, [field]: val } : it)));
  };

  const handleEdit = useCallback(() => {
    snapshotRef.current = cloneItems(items);
    setFormMode(FormMode.Edit);
  }, [items]);

  const handleCreate = useCallback(() => {
    snapshotRef.current = cloneItems(items);
    setFormMode(FormMode.Create);
  }, [items]);

  const handleCancel = useCallback(() => {
    setItems(cloneItems(snapshotRef.current));
    setFormMode(FormMode.View);
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    try {
      await ktService.saveOpeningBalances({ year: Number(year), items });
      dispatchAppToast(dispatch, { message: labels.saveSuccess, type: 'success' });
      setFormMode(FormMode.View);
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, labels.saveError), type: 'error' });
    } finally {
      setSaving(false);
    }
  }, [year, items, dispatch, load]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(() => {
    if (formMode === FormMode.Create) return labels.createHint;
    if (formMode === FormMode.Edit) return labels.editHint;
    return labels.viewHint;
  }, [formMode]);

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        disabled: isEditing,
        onClick: load,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];

    if (isView) {
      const right: LinListToolbarActionDef[] = canWrite
        ? (hasRows
          ? [{
            id: 'edit',
            placement: 'right',
            action: 'edit',
            visible: true,
            onClick: handleEdit,
            testId: `${TEST_ID}-toolbar-edit-btn`,
          }]
          : [{
            id: 'create',
            placement: 'right',
            action: 'create',
            variant: 'primary',
            visible: true,
            onClick: handleCreate,
            testId: `${TEST_ID}-toolbar-add-btn`,
          }])
        : [];
      return [...left, ...right];
    }

    return [
      ...left,
      {
        id: 'cancel',
        placement: 'right',
        label: labels.cancel,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: handleCancel,
        testId: `${TEST_ID}-toolbar-cancel-btn`,
      },
      {
        id: 'save',
        placement: 'right',
        visible: true,
        testId: `${TEST_ID}-toolbar-save-btn`,
        render: () => (
          <Button
            variant="primary"
            size="sm"
            loading={saving}
            disabled={saving}
            data-testid={`${TEST_ID}-save`}
            onClick={handleSave}
          >
            {labels.save}
          </Button>
        ),
      },
    ];
  }, [
    isView,
    isEditing,
    hasRows,
    canWrite,
    load,
    handleEdit,
    handleCreate,
    handleCancel,
    handleSave,
    saving,
  ]);

  const listFilters = useMemo(
    () => (
      <ErpListHeaderFilters
        testIdPrefix={TEST_ID}
        filterCols={2}
        filterMaxWidthPx={1000}
      >
        <div className={erp.field} data-testid={`${TEST_ID}-field-year`}>
          <Select
            label={labels.filterYear}
            value={year}
            onChange={e => setYear(e.target.value)}
            options={yearOptions()}
            disabled={isEditing}
            data-testid={`${TEST_ID}-year`}
          />
        </div>
      </ErpListHeaderFilters>
    ),
    [year, isEditing],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty(year)}</div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table`}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>{labels.colAccount}</th>
            <th>{labels.colAccountName}</th>
            <th>{labels.colCustomer}</th>
            <th className={erp.colRight}>{labels.colDebit}</th>
            <th className={erp.colRight}>{labels.colCredit}</th>
          </tr>
        </thead>
        <tbody>
          {items.map((it, idx) => (
            <tr key={`${it.accountCode}-${it.customerId ?? idx}`} data-testid={`${TEST_ID}-row-${idx + 1}`}>
              <td><code>{it.accountCode}</code></td>
              <td>{it.accountName}</td>
              <td>{it.customerName ?? '—'}</td>
              <td className={erp.colRight}>
                {isView ? (
                  <span data-testid={`${TEST_ID}-row-${idx + 1}-debit`}>{formatVnd(it.debitBalance)}</span>
                ) : (
                  <MoneyInput
                    value={it.debitBalance}
                    onChange={val => updateItem(idx, 'debitBalance', val)}
                    data-testid={`${TEST_ID}-row-${idx + 1}-debit`}
                  />
                )}
              </td>
              <td className={erp.colRight}>
                {isView ? (
                  <span data-testid={`${TEST_ID}-row-${idx + 1}-credit`}>{formatVnd(it.creditBalance)}</span>
                ) : (
                  <MoneyInput
                    value={it.creditBalance}
                    onChange={val => updateItem(idx, 'creditBalance', val)}
                    data-testid={`${TEST_ID}-row-${idx + 1}-credit`}
                  />
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
      data-form-mode={formMode}
    >
      <LinPageLayout
        kind="catalog"
        filterBarLayout="compact"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-balance-scale',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        filters={listFilters}
        filterMaxWidthPx={1000}
        filtersTestId={`${TEST_ID}-filters`}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SoDuDauKyPage;
